+/**
+ * Webhook channel handler — delivers event payloads to registered webhook URLs.
+ *
+ * Subscribes to the EventBus following the same pattern as NotificationService.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type {
+  OrderCreatedEvent,
+  OrderStatusChangedEvent,
+  AppEvent,
+} from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookDelivery {
+  id: string;
+  url: string;
+  eventType: string;
+  payload: Record<string, unknown>;
+  deliveredAt: Date;
+}
+
+let nextId = 1;
+
+function generateWebhookDeliveryId(): string {
+  return `whd-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetWebhookDeliveryIdCounter(): void {
+  nextId = 1;
+}
+
+export class WebhookChannelService {
+  private logger = new Logger('WebhookChannelService');
+  private deliveries: WebhookDelivery[] = [];
+  private registeredUrls: string[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.registerHandlers();
+  }
+
+  private registerHandlers(): void {
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      this.handleOrderCreated(event);
+    });
+
+    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      this.handleOrderStatusChanged(event);
+    });
+  }
+
+  private handleOrderCreated(event: OrderCreatedEvent): void {
+    this.deliverToAll(event.type, {
+      orderId: event.order.id,
+      userId: event.user.id,
+      userEmail: event.user.email,
+      items: event.order.items.map((item) => ({
+        productId: item.productId,
+        name: item.name,
+        quantity: item.quantity,
+        unitPrice: item.unitPrice,
+      })),
+      total: event.order.total,
+      timestamp: event.timestamp.toISOString(),
+    });
+  }
+
+  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
+    this.deliverToAll(event.type, {
+      orderId: event.order.id,
+      userId: event.order.userId,
+      previousStatus: event.previousStatus,
+      newStatus: event.newStatus,
+      timestamp: event.timestamp.toISOString(),
+    });
+  }
+
+  private deliverToAll(eventType: string, payload: Record<string, unknown>): void {
+    for (const url of this.registeredUrls) {
+      this.deliver(url, eventType, payload);
+    }
+  }
+
+  private deliver(
+    url: string,
+    eventType: string,
+    payload: Record<string, unknown>,
+  ): void {
+    const delivery: WebhookDelivery = {
+      id: generateWebhookDeliveryId(),
+      url,
+      eventType,
+      payload,
+      deliveredAt: new Date(),
+    };
+    this.deliveries.push(delivery);
+    this.logger.info(`Webhook delivered: ${delivery.id} to ${url} for ${eventType}`);
+  }
+
+  registerUrl(url: string): void {
+    if (!this.registeredUrls.includes(url)) {
+      this.registeredUrls.push(url);
+      this.logger.info(`Webhook URL registered: ${url}`);
+    }
+  }
+
+  unregisterUrl(url: string): void {
+    this.registeredUrls = this.registeredUrls.filter((u) => u !== url);
+    this.logger.info(`Webhook URL unregistered: ${url}`);
+  }
+
+  getRegisteredUrls(): string[] {
+    return [...this.registeredUrls];
+  }
+
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  getDeliveriesForUrl(url: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.url === url);
+  }
+
+  getDeliveryCount(): number {
+    return this.deliveries.length;
+  }
+
+  clearDeliveries(): void {
+    this.deliveries = [];
+  }
+}

